ll a[N], b[N], prea[N], preb[N];
void solve(int CASE)
{
	ll n; cin >> n;
	fa(i, 1, n)cin >> a[i], a[i + n] = a[i];
	fa(i, 1, n)cin >> b[i], b[i + n] = b[i];
	var Q = priority_queue<pll, vector<pll>, greater<pll>>();
	fa(i, 1, 2 * n) {
		prea[i] = prea[i - 1] + a[i];
		preb[i] = preb[i - 1] + b[i];
		ll now = preb[i] - prea[i];
		while (Q.size() and i - Q.top().py + 1 >= n)Q.pop(); // 长度 >= n 的不要了
		if (Q.size()) {
			if (now + Q.top().px < 0) {
				cout << "NO" << endl;
				return;
			}
		}
		Q.push({ prea[i] - preb[i - 1],i });
	}
	if (prea[n] > preb[n]) { // 单独测长度为 n 的
		cout << "NO" << endl;
		return;
	}
	cout << "YES" << endl;
	return;
}
